# BAD: pure Python loop — VM overhead per iteration
def dot_product_slow(a: list, b: list) -> float:
    return sum(x * y for x, y in zip(a, b))

# GOOD: NumPy — single C call, no per-element Python overhead
import numpy as np

def dot_product_fast(a: np.ndarray, b: np.ndarray) -> float:
    return float(np.dot(a, b))  # BLAS-optimized single C call

# For 10 million elements:
# slow: ~1.2s  |  fast: ~0.005s  (240x speedup)
